849	  // (과제2) 폴더가 바뀌면 상태 필터 개수도 그 폴더 기준으로 다시 집계 → 칩 배지 즉시 갱신.
850	  renderMxFilters(kind);
851	  renderMatrix(kind);
852	  // (이슈2) 폴더가 바뀌면 카테고리 칩 개수도 그 폴더 범위로 다시 집계해야 하므로 칩 바를 갱신한다.
853	  loadTags();
854	}
855	
856	// F4/F5: [전체] 선택 시에만 경로 컬럼을 보여준다(폴더 선택 시 숨김 — 좌측이 대체). (kind 공용)
857	function applyScopeColumn(kind) {
858	  const tbl = $('#' + kind + '-mx-table');
859	  if (!tbl) return;
860	  tbl.classList.toggle('mx-hide-scope', mxState[kind].folder != null);
861	}
862	
863	// 폴더 리스트 검색 입력. (kind 공용)
864	function applyFolderSearch(kind, q) {
865	  mxState[kind].folderQ = q;
866	  renderFolderList(kind);
867	}
868	
869	// 상태(syncState)별 개수를 집계한다. rows 배열을 받아 {synced,drift,partial,single} 개수를 센다.
870	// (과제2) 서버가 준 전체 counts 대신 이 함수로 "선택된 폴더 기준" rows를 집계한다.
871	function stateCounts(rows) {
872	  const c = { synced: 0, drift: 0, partial: 0, single: 0 };
873	  for (const r of rows || []) c[r.syncState] = (c[r.syncState] || 0) + 1;
874	  return c;
875	}
876	
877	// 상태 필터 칩 렌더(개수 배지). (과제2) 개수는 선택된 폴더 기준(mxScopedRows)으로 계산한다 —
878	// 폴더 클릭(selectFolder) 시 renderMxFilters가 다시 불려 즉시 갱신된다. 폴더 미선택 시 전체 집계.
879	function renderMxFilters(kind) {
880	  const box = $('#' + kind + '-mx-state');
881	  if (!box) return;
882	  const st = mxState[kind];
883	  const c = stateCounts(mxScopedRows(kind));
884	  box.innerHTML = MX_FILTERS.map((f) => {
885	    const n = f.states ? f.states.reduce((a, s) => a + (c[s] || 0), 0) : ((c.synced || 0) + (c.drift || 0) + (c.partial || 0) + (c.single || 0));
886	    return `<button class="filter-pill ${st.filter === f.key ? 'active' : ''}" data-mx-filter="${kind}:${f.key}">${esc(f.ko)}<span class="fp-count">${n}</span></button>`;
887	  }).join('');
888	}
889	
890	function renderMxContext(kind, visibleCount) {
891	  const box = $('#' + kind + '-mx-context');
892	  if (!box) return;
893	  const st = mxState[kind];
894	  // 분모(total): skill이 폴더를 선택한 상태면 그 폴더의 스킬 수, 아니면 전체.
895	  const total = mxScopedRows(kind).length;
896	  const filter = MX_FILTERS.find((x) => x.key === st.filter) || MX_FILTERS[1];
897	  // 폴더 선택 표시(skill·agent 공용) + 다중 태그 표시.
898	  const folder = st.folder
899	    ? ` · 폴더 ${st.folder === 'global' ? '전역(~)' : baseName(st.folder)}` : '';
900	  // (과제1) 컨텍스트에 태그명 표시 — 특수 키 UNTAGGED_KEY는 사람이 읽는 "미정"으로 치환.
901	  const tag = activeTags.size ? ` · 태그 ${[...activeTags].map((t) => t === UNTAGGED_KEY ? '미정' : t).join(', ')}` : '';
902	  const q = st.q ? ` · 검색 "${st.q}"` : '';
903	  box.innerHTML = `<span>현재 <b>${esc(filter.ko)}</b>${esc(folder)}${esc(tag)}${esc(q)} 표시 중 · <b>${visibleCount}/${total}</b>개</span>
904	    <span class="mx-legend">
905	      <span class="mx-legend-item"><b>✓</b> 있음</span>
906	      <span class="mx-legend-item"><span class="mx-dot sg-1"></span> 같은 색 = 같은 내용</span>
907	      <span class="mx-legend-item"><span class="mx-cell-no">✗</span> 없음</span>
908	    </span>`;
909	}
910	
911	// 폴더(scope)만 적용한 행 — 컨텍스트 분모/폴더 범위 계산용. folder가 null이면 전체. (kind 공용)
912	function mxScopedRows(kind) {
913	  const st = mxState[kind];
914	  const rows = (st.data && st.data.rows) || [];
915	  if (st.folder) return rows.filter((r) => r.scope === st.folder);
916	  return rows;
917	}
918	
919	// 현재 폴더·상태 필터·검색·태그로 걸러진 뒤, 미동기화 상단 정렬한 행.
920	function mxVisibleRows(kind) {
921	  const st = mxState[kind];
922	  const f = MX_FILTERS.find((x) => x.key === st.filter) || MX_FILTERS[1];
923	  const q = (st.q || '').trim().toLowerCase();
924	  const filtered = mxScopedRows(kind).filter((r) => {
925	    if (f.states && !f.states.includes(r.syncState)) return false;
926	    if (q && !String(r.name).toLowerCase().includes(q)) return false;
927	    if (!tagMatch(r)) return false; // 다중 태그(OR) 필터 연동
928	    return true;
929	  });
930	  // F4: 미동기화 상단 정렬(drift→partial→single→synced). 동률이면 이름순(안정적 표시).
931	  return filtered.slice().sort((a, b) => {
932	    const oa = MX_STATE_ORDER[a.syncState] ?? 9, ob = MX_STATE_ORDER[b.syncState] ?? 9;
933	    if (oa !== ob) return oa - ob;
934	    return a.name < b.name ? -1 : a.name > b.name ? 1 : 0;
935	  });
936	}
937	
938	// 도구 열 셀: 존재 시 ✓ + 그룹 색점(같은 색=내용 동일), 없으면 ✗.
939	// F5(agent): nonstandard(도구가 읽지 않는 위치의 파일) → "⚠ 비표준" 배지(툴팁)로 은은히 구분.
940	function mxToolCell(slot) {
941	  if (slot && slot.exists) {
942	    return `<span class="mx-cell-yes">✓<span class="mx-dot ${syncGroupClass(slot.group)}"></span></span>`;
943	  }
944	  if (slot && slot.nonstandard) {
945	    return `<span class="mx-cell-nonstd" title="이 도구가 읽지 않는 위치입니다(비표준)">⚠ 비표준</span>`;
946	  }
947	  return '<span class="mx-cell-no">✗</span>';
948	}
949	
950	// 경로 셀: 폴더명(전역이면 "전역(~)")만 표시, title에 전체 경로.
951	function mxScopeCell(r) {
952	  if (r.scope === 'global') return `<span class="mx-scope global" title="전역 홈(~)">전역(~)</span>`;
953	  const folder = baseName(r.scope);
954	  return `<span class="mx-scope" title="${esc(r.scope)}">📁 <span class="mxs-folder">${esc(folder)}</span></span>`;
955	}
956	
957	// 동기화 열: 상태 배지 + (단독·동기화됨이 아니면) [동기화] 버튼. 단독도 "다른 도구로 보내기"용 [동기화] 노출.
958	function mxSyncCell(kind, r) {
959	  const s = MX_SYNC[r.syncState] || MX_SYNC.single;
960	  const badge = `<span class="badge ${s.badge}">${s.ic} ${esc(s.ko)}</span>`;
961	  // 동기화됨은 이미 일치 → 버튼 없이 상태만. 나머지(불일치/일부없음/단독)는 [동기화] 노출.
962	  // data-sync-source는 생략: skill의 sourceId는 서버가 baseTool→공식 소스로 정확히 유도한다
963	  //   (임의 도구명을 sourceId로 넘기면 skillPull이 소스를 못 찾음). 기준 도구 자동선택은
964	  //   sync 모달이 lastSyncBase/baseCandidates로 처리한다.
965	  const btn = r.syncState === 'synced' ? ''
966	    : `<button class="btn btn-secondary btn-sm" data-sync-open="${kind}" data-sync-name="${esc(r.name)}" data-sync-scope="${esc(r.scope)}">동기화</button>`;
967	  return `<div class="mx-sync">${badge}${btn}</div>`;
968	}
969	
970	// 행에서 존재하는 첫 도구 = 배치/단건 동기화 기본 기준(base).
971	function mxRowBase(r) {
972	  return TOOLS.find((t) => r.tools[t] && r.tools[t].exists) || 'claude';
973	}
974	
975	function renderMatrix(kind) {
976	  const st = mxState[kind];
977	  const body = $('#' + kind + '-mx-rows');
978	  if (!body) return;
979	  applyScopeColumn(kind); // 경로 컬럼 노출은 [전체] 선택 시에만 (skill·agent 공용)
980	  const all = mxVisibleRows(kind);
981	  renderMxContext(kind, all.length);
982	  const shown = all.slice(0, st.page * MX_PAGE);
983	  if (!all.length) {
984	    const empty = (st.data && (st.data.rows || []).length)
985	      ? '조건에 맞는 항목이 없습니다 — 필터/검색을 바꿔보세요'
986	      : `아직 ${kind === 'skill' ? '스킬' : '에이전트'}이 하나도 없어요 — 프로젝트를 추가하면 그 안의 스킬이 자동으로 보입니다
987	        <span class="inline-acts" style="justify-content:center;margin-top:10px">
988	          <button class="btn btn-secondary btn-sm" data-open-projects="1">📁 프로젝트 관리</button>
989	        </span>`;
990	    body.innerHTML = `<tr><td colspan="${mxColspan(kind)}" class="skel">${empty}</td></tr>`;
991	    if ($('#' + kind + '-mx-more')) $('#' + kind + '-mx-more').innerHTML = '';
992	    const allc = $('#' + kind + '-mx-all'); if (allc) allc.checked = false;
993	    return;
994	  }
995	  body.innerHTML = shown.map((r) => {
996	    const rowErr = r.error ? ` <span class="badge warn" title="${esc(r.error)}">⚠ 이슈</span>` : '';
997	    return `<tr class="mx-row-${esc(r.syncState)}" data-mx-row="${kind}" data-mx-name="${esc(r.name)}" data-mx-scope="${esc(r.scope)}">
998	      <td class="cell"><input type="checkbox" class="mx-pick" data-mx-kind="${kind}" data-mx-name="${esc(r.name)}" data-mx-base="${esc(mxRowBase(r))}" data-mx-scope="${esc(r.scope)}" /></td>
999	      <td class="mx-scope-cell">${mxScopeCell(r)}</td>
1000	      <td><span class="item-name item-name-link" data-view-content="${kind}" data-view-name="${esc(r.name)}" data-view-scope="${esc(r.scope)}" title="내용 보기">${esc(r.name)}</span>${rowErr}</td>
1001	      <td>${tagChipsHtml(r.tags, r.autoTags)}</td>
1002	      <td class="mx-tool">${mxToolCell(r.tools.claude)}</td>
1003	      <td class="mx-tool">${mxToolCell(r.tools.codex)}</td>
1004	      <td>${mxSyncCell(kind, r)}</td>
1005	    </tr>`;
1006	  }).join('');
1007	  // 더보기(50행 단위).
1008	  const more = $('#' + kind + '-mx-more');
1009	  if (more) {
1010	    more.innerHTML = shown.length < all.length
1011	      ? `<span class="muted">${shown.length} / ${all.length}개 표시 중</span><button class="btn btn-ghost btn-sm" data-mx-more="${kind}">더보기 (+${Math.min(MX_PAGE, all.length - shown.length)})</button>`
1012	      : (all.length > MX_PAGE ? `<span class="muted">${all.length}개 모두 표시됨</span>` : '');
1013	  }
1014	  const allc = $('#' + kind + '-mx-all'); if (allc) allc.checked = false;
1015	  if ($('#' + kind + '-mx-progress')) $('#' + kind + '-mx-progress').textContent = '';
1016	}
1017	
1018	// 상태 필터 칩 클릭.
1019	function applyMxFilter(kind, key) {
1020	  mxState[kind].filter = key;
1021	  mxState[kind].page = 1;
1022	  renderMxFilters(kind);
1023	  renderMatrix(kind);
1024	}
1025	// 이름 검색 입력.
1026	function applyMxSearch(kind, q) {
1027	  mxState[kind].q = q;
1028	  mxState[kind].page = 1;
1029	  renderMatrix(kind);
1030	}
1031	// 더보기.
1032	function mxMore(kind) { mxState[kind].page += 1; renderMatrix(kind); }
1033	
1034	async function doSkillPull(name, sourceId, piAck) {
1035	  currentSkillPull = { name, source_id: sourceId }; currentPullTool = null; currentAgentPull = null; currentSync = null; currentStoreApply = null;
1036	  const res = await fetch('/skills/pull', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name, source_id: sourceId, piAck }) });
1037	  if (res.status === 409) { showPiModal(await res.json()); return; } // PI 게이트 흐름 보존
1038	  if (!res.ok) { toast('적용하지 못했습니다: ' + (await errMsg(res))); return; }
1039	  await res.json();
1040	  $('#pi-modal').hidden = true;
1041	  toast('스킬 가져오기 완료');
1042	  loadSkillOverview();
1043	}
1044	
1045	// (과제3) 스킬 슬라이드오버(openSkillDetail) 제거 — 행 클릭·이름 클릭 모두 중앙 본문 뷰어(openContentViewer)를
1046	// 연다. 스킬 diff/apply/태그수정은 뷰어의 좌우 diff + 동기화 모달 흐름으로 대체된다.
1047	// (doSkillDiff/doSkillApply/doSkillApplyAll 핸들러는 동기화 모달의 [차이 보기] 등에서 계속 쓰인다.)
1048	
1049	async function doSkillDiff(name, to) {
1050	  let d;
1051	  try { d = await api('/skills/diff?name=' + encodeURIComponent(name) + '&to=' + encodeURIComponent(to)); }
1052	  catch (e) { toast('미리보기를 불러오지 못했습니다: ' + e.message); return; }
1053	  let body;
1054	  if (!d.canonicalExists) body = '<div class="empty-state">중앙 저장소에 해당 skill이 없습니다.</div>';
1055	  else if (!d.hasChanges) body = '<div class="empty-state">차이 없음 — 이미 동일</div>';
1056	  else body = renderDiff(d.diff);
1057	  $('#skill-inline-diff').innerHTML = `<div class="divider-strong"></div><div class="sub-label">${esc(name)} → ${esc(to)}</div>${lossBanner(d.losses)}${body}`;
1058	  $('#skill-inline-diff').scrollIntoView({ behavior: 'smooth', block: 'nearest' });
1059	}
1060	
1061	async function doSkillApply(name, to) {
1062	  // #2: 미리보기 패널(openSkillDetail)을 거친 적용 — native confirm() 제거.
1063	  try {
1064	    const r = await api('/skills/push', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name, to, apply: true }) });
1065	    toast(`${to} 적용 완료 · 백업: ` + (r.backupPath || '(신규)'));
1066	    loadSkillOverview();
1067	  } catch (e) {
1068	    toast('적용하지 못했습니다: ' + e.message);
1069	  }
1070	}
1071	
1072	// #1: 세 도구에 한 번에 적용(skill). TOOLS 순회로 기존 /skills/push(apply:true)를 호출·합산.
1073	// 부분 실패는 도구별로 표시하고 중단하지 않는다(D26-②).
1074	async function doSkillApplyAll(name) {
1075	  await applyAll({
1076	    outSel: '#skill-apply-all-result',
1077	    endpoint: '/skills/push',
1078	    payload: (to) => ({ name, to }),
1079	    reload: () => loadSkillOverview(),
1080	  });
1081	}
1082	
1083	// ===================== 에이전트(agents) — 상세/pull 핸들러(매트릭스는 loadMatrix가 렌더) =====================
1084	async function doAgentPull(from, name, piAck) {
1085	  currentAgentPull = { from, name }; currentPullTool = null; currentSkillPull = null; currentSync = null; currentStoreApply = null;
1086	  const res = await fetch('/agents/pull', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ from, name, piAck }) });
1087	  if (res.status === 409) { showPiModal(await res.json()); return; } // PI 게이트 흐름 보존
1088	  if (!res.ok) { toast('적용하지 못했습니다: ' + (await errMsg(res))); return; }
1089	  await res.json();
1090	  $('#pi-modal').hidden = true;
1091	  toast('에이전트 가져오기 완료');
1092	  loadAgentOverview();
1093	}
1094	
1095	// 슬라이드오버: 도구별 tstat + tools 칩 + loss-banner + diff + push
1096	async function openAgentDetail(id) {
1097	  let ag, d;
1098	  try {
1099	    ag = await api('/agents/overview');
1100	    d = await Promise.all(TOOLS.map((to) =>
1101	      api('/agents/diff?id=' + encodeURIComponent(id) + '&to=' + encodeURIComponent(to)).then((x) => ({ to, ...x }))
1102	    ));
1103	  } catch (e) { toast('상세를 불러오지 못했습니다: ' + e.message); return; }
1104	  const meta = (ag.canonicalAgents || []).find((a) => a.id === id) || { name: id, tools: [], tags: [] };
1105	  const allLosses = [];
1106	  const rows = d.map((x) => {
1107	    (x.losses || []).forEach((l) => allLosses.push(`[${x.to}] ${l}`));
1108	    const state = !x.canonicalExists ? '없음' : (x.hasChanges ? '변경 있음' : '동일');
1109	    const reason = (x.losses || []).length ? `<div class="tstat-reason">손실: ${x.losses.map(esc).join(', ')}</div>` : '';
1110	    return `<div class="tstat-row">
1111	        <span class="tool-dot" style="background:${TOOL_COLOR[x.to]}"></span>
1112	        <span class="tool-name">${x.to}</span>
1113	        <span class="muted" style="margin-left:auto">${state}</span>
1114	        <button class="btn btn-secondary btn-sm" data-agent-diff-id="${esc(id)}" data-agent-diff-to="${x.to}">diff</button>
1115	        <button class="btn btn-secondary btn-sm" data-agent-apply="${esc(id)}" data-agent-apply-to="${x.to}" ${x.canonicalExists ? '' : 'disabled'}>적용</button>
1116	      </div>${reason}`;
1117	  }).join('');
1118	  const toolChips = (meta.tools || []).map((t) => `<span class="tool-chip" style="color:${TOOL_COLOR[t] || 'var(--st-muted)'};background:${TOOL_SOFT[t] || 'var(--st-muted-soft)'}">${esc(t)}</span>`).join(' ');
1119	  const anyCanon = d.some((x) => x.canonicalExists);
1120	  openPanel({
1121	    title: meta.name,
1122	    meta: `<span class="kv"><b>출처</b> ${esc(meta.source_tool || '—')}</span>`,
1123	    bodyHtml: lossBanner(allLosses)
1124	      + (toolChips ? `<div class="sub-label">대상 모델</div><div class="chip-list">${toolChips}</div><div style="height:14px"></div>` : '')
1125	      + refSkillsSection(meta.name)
1126	      + '<div class="sub-label">모델별 상태</div><div class="tstat">' + rows + '</div><div id="agent-apply-all-result"></div><div id="agent-inline-diff"></div>',
1127	    footHtml: `<button class="btn btn-primary" data-sync-open="agent" data-sync-name="${esc(meta.name)}">동기화</button><button class="btn btn-secondary" data-agent-apply-all="${esc(id)}" ${anyCanon ? '' : 'disabled'}>중앙 저장소 → 세 모델</button><button class="btn btn-ghost" data-view-open="agent" data-view-name="${esc(meta.name)}" data-view-scope="${esc(mxScopeOf('agent', meta.name))}">내용 보기</button><button class="btn btn-ghost" data-tag-kind="agent" data-tag-id="${esc(id)}">태그 수정</button><button class="btn btn-ghost" id="panel-cancel">닫기</button>`,
1128	  });
1129	}
