// 사용빈도 전용 표. GET /usage → items[]{ id, kind, freq:{day1,day7,total}, lastUsed }.
// 컬럼: 이름 · 최근 사용(lastUsed) · 일주일 사용빈도(freq.day7). (하루·전체 컬럼 제거.)
// 백엔드 계약: 각 item에 freq가 붙는다. 구 응답에서는 freq가 없을 수 있으므로 항상 `|| 0`으로 안전 소비.
// 정렬: 최근 사용(lastUsed) 최신순. lastUsed가 없는 항목은 아래로. 0인 항목도 표시한다.
async function loadUsage() {
  showLoading('#usage-rows', 3, '사용 기록을 세고 있습니다 — 조금만 기다려주세요…');
  let u;
  // /usage = Claude 세션 기록에서 스킬 호출 "횟수"만 집계(B 신호, 본문은 읽지 않음).
  // 개요의 "지난 1일/7일 사용"과 같은 소스 → 두 화면 숫자가 일치한다.
  try { u = await api('/usage'); }
  catch { showLoadError('#usage-rows', loadUsage, 3); return; }
  const items = (u.items || []).slice().sort((a, b) => {
    // 최근 사용(lastUsed) 최신이 맨 위. 없는 항목(0)은 아래로 밀린다.
    const la = a.lastUsed ? new Date(a.lastUsed).getTime() : 0;
    const lb = b.lastUsed ? new Date(b.lastUsed).getTime() : 0;
    if (lb !== la) return lb - la;
    // 동률(둘 다 없음 포함)은 이름순으로 안정적 표시.
    return a.name < b.name ? -1 : a.name > b.name ? 1 : 0;
  });
  const note = $('#usage-note');
  if (note) {
    note.textContent = u.source === 'none'
      ? '아직 집계된 사용 기록이 없습니다 — Claude로 스킬을 쓰면 여기에 횟수가 쌓입니다.'
      : 'Claude 세션 기록에서 스킬을 몇 번 썼는지 셉니다(대화 내용은 읽지 않음 · 횟수만).';
  }
  $('#usage-rows').innerHTML = items.length ? items.map((x) => {
    const f = x.freq || {};
    return `<tr>
      <td><span class="item-name">${esc(x.name)}</span></td>
      <td>${formatDateHuman(x.lastUsed)}</td>
      <td class="use-cell">${esc(String(f.day7 || 0))}</td>
    </tr>`;
  }).join('') : `<tr><td colspan="3" class="skel">스킬이 없습니다
    <span class="inline-acts" style="justify-content:center;margin-top:10px"><button class="btn btn-secondary btn-sm" data-goto="skills">스킬 보기</button></span></td></tr>`;
}

input.old_string:
// ===================== 백업 / 복구(#4, UX-D1 API 소비) =====================
// GET /backups → 타임스탬프 폴더별 entries(파일·원위치·도구·항목·시각). 최신순.
// 상위 BACKUP_SHOW개(엔트리 기준)만 먼저 보이고 [더보기]로 나머지를 펼친다.
const BACKUP_SHOW = 8;
let backupsExpanded = false;
let lastBackups = []; // 평탄화된 엔트리 캐시(복구 확인 모달에서 참조).
let restoreTarget = null; // {backupFilePath, targetPath}

async function loadBackups() {
  const box = $('#backups-list');
  if (!box) return;
  backupsExpanded = false;
  showLoading('#backups-list');
  let d;
  try { d = await api('/backups'); }
  catch { showLoadError('#backups-list', loadBackups); return; }
  // 폴더별 entries를 시각 순(최신 폴더 우선)으로 평탄화한다.
  const flat = [];
  for (const grp of (d.backups || [])) {
    for (const e of (grp.entries || [])) flat.push({ ...e, timestamp: grp.timestamp });
  }
  lastBackups = flat;
  renderBackups();
}

function renderBackups() {
  const box = $('#backups-list');
  if (!box) return;
  if (!lastBackups.length) {
    box.innerHTML = '<div class="empty-state">아직 백업이 없습니다 — 적용/동기화하면 자동으로 생깁니다.</div>';
    return;
  }
  const shown = backupsExpanded ? lastBackups : lastBackups.slice(0, BACKUP_SHOW);
  const rows = shown.map((e, i) => {
    const when = e.at ? new Date(e.at).toLocaleString() : (e.timestamp || '–');
    const item = e.item ? `${esc(e.item)}` : (e.file ? esc(e.file) : '–');
    const kindTool = [e.kind, e.tool].filter(Boolean).map(esc).join(' · ') || '–';
    const act = e.restorable
      ? `<button class="btn btn-secondary btn-sm" data-backup-restore="${i}">복구</button>`
      : `<span class="badge muted" title="원위치 정보(manifest)가 없어 복구할 수 없습니다">복구 불가</span>`;
    return `<div class="card backup-row ${e.restorable ? '' : 'unrestorable'}">
      <div class="backup-main">
        <div class="item-name">${item}</div>
        <div class="item-meta">${esc(when)} · ${kindTool}${e.size != null ? ` · ${esc(String(e.size))}B` : ''}</div>
        <div class="item-meta backup-target">${e.targetPath ? esc(e.targetPath) : '원위치 정보 없음'}</div>
      </div>
      <div class="backup-act">${act}</div>
    </div>`;
  }).join('');
  const more = (!backupsExpanded && lastBackups.length > BACKUP_SHOW)
    ? `<div class="inline-acts" style="justify-content:center"><button class="btn btn-ghost btn-sm" data-backup-more="1">더보기 (${lastBackups.length - BACKUP_SHOW})</button></div>`
    : '';
  box.innerHTML = rows + more;
}

// [복구] 클릭 → 확인 모달. 실제 복구는 확인 시 doBackupRestore().
function openRestoreModal(idx) {
  const e = lastBackups[Number(idx)];
  if (!e || !e.restorable) return;
  restoreTarget = { backupFilePath: e.backupFilePath, targetPath: e.targetPath };
  $('#restore-target').textContent = `복구 위치: ${e.targetPath}`;
  $('#restore-modal').hidden = false;
}

async function doBackupRestore() {
  if (!restoreTarget) return;
  $('#restore-modal').hidden = true;
  try {
    const r = await api('/backups/restore', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ path: restoreTarget.backupFilePath }) });
    toast('복구됨 → ' + (r.targetPath || restoreTarget.targetPath || ''));
  } catch (e) {
    toast('복구하지 못했습니다: ' + e.message);
  }
  restoreTarget = null;
  loadBackups(); // 복구 전 재백업이 생겼으니 목록 갱신.
  loadUsage();
}

